// src/components/Navbars/AuthNavbar.js
import React, { useState } from "react";
import { Link, useHistory } from "react-router-dom";

export default function AuthNavbar() {
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const history = useHistory();

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      history.push(`/search?q=${encodeURIComponent(searchQuery)}`);
      setSearchQuery("");
      setIsSearchOpen(false);
    }
  };

  return (
    <>
      <nav className="auth-navbar">
        <div className="navbar-container">
          {/* Logo */}
          <Link to="/" className="navbar-logo">
            <span className="logo-icon">🍽️</span>
            <span className="logo-text">StyleMe</span>
          </Link>

          {/* Desktop Navigation Links */}
          <div className="navbar-links">
            <Link to="/" className="nav-link">Accueil</Link>
            <Link to="/restaurants" className="nav-link">Restaurants</Link>
            <Link to="/employees" className="nav-link">Employés</Link>
            <Link to="/managers" className="nav-link">Managers</Link>
            <Link to="/landing" className="nav-link">À propos</Link>
          </div>

          {/* Search Bar */}
          <div className={`navbar-search ${isSearchOpen ? "open" : ""}`}>
            <form onSubmit={handleSearch}>
              <input
                type="text"
                placeholder="Rechercher..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onFocus={() => setIsSearchOpen(true)}
                onBlur={() => setTimeout(() => setIsSearchOpen(false), 200)}
              />
              <button type="submit">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="11" cy="11" r="8" />
                  <line x1="21" y1="21" x2="16.65" y2="16.65" />
                </svg>
              </button>
            </form>
          </div>

          {/* Right Side Buttons */}
          <div className="navbar-actions">
            <Link to="/auth/login" className="nav-btn-login">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4" />
                <polyline points="10 17 15 12 10 7" />
                <line x1="15" y1="12" x2="3" y2="12" />
              </svg>
              <span>Se connecter</span>
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <button className="mobile-menu-btn">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="3" y1="12" x2="21" y2="12" />
              <line x1="3" y1="6" x2="21" y2="6" />
              <line x1="3" y1="18" x2="21" y2="18" />
            </svg>
          </button>
        </div>
      </nav>

      <style jsx>{`
        .auth-navbar {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          z-index: 1000;
          background: rgba(0, 0, 0, 0.7);
          backdrop-filter: blur(12px);
          border-bottom: 1px solid rgba(255, 255, 255, 0.08);
          padding: 0 20px;
          height: 56px;
        }
        
        .navbar-container {
          max-width: 1400px;
          margin: 0 auto;
          display: flex;
          align-items: center;
          justify-content: space-between;
          height: 100%;
          gap: 20px;
        }
        
        /* Logo */
        .navbar-logo {
          display: flex;
          align-items: center;
          gap: 8px;
          text-decoration: none;
          transition: all 0.3s;
          flex-shrink: 0;
        }
        
        .navbar-logo:hover {
          transform: scale(1.02);
        }
        
        .logo-icon {
          font-size: 1.5rem;
        }
        
        .logo-text {
          font-size: 1.2rem;
          font-weight: bold;
          background: linear-gradient(135deg, white, #a855f7);
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
        }
        
        /* Navigation Links */
        .navbar-links {
          display: flex;
          align-items: center;
          gap: 24px;
        }
        
        .nav-link {
          color: rgba(255, 255, 255, 0.7);
          text-decoration: none;
          font-size: 0.85rem;
          font-weight: 500;
          transition: all 0.3s;
          white-space: nowrap;
        }
        
        .nav-link:hover {
          color: white;
        }
        
        /* Search Bar */
        .navbar-search {
          flex: 1;
          max-width: 300px;
        }
        
        .navbar-search form {
          position: relative;
          width: 100%;
        }
        
        .navbar-search input {
          width: 100%;
          padding: 6px 32px 6px 36px;
          background: rgba(255, 255, 255, 0.08);
          border: 1px solid rgba(255, 255, 255, 0.15);
          border-radius: 30px;
          color: white;
          font-size: 0.8rem;
          outline: none;
          transition: all 0.3s;
        }
        
        .navbar-search input:focus {
          background: rgba(255, 255, 255, 0.12);
          border-color: #a855f7;
          box-shadow: 0 0 0 2px rgba(168, 85, 247, 0.2);
        }
        
        .navbar-search input::placeholder {
          color: rgba(255, 255, 255, 0.4);
          font-size: 0.75rem;
        }
        
        .navbar-search button {
          position: absolute;
          left: 10px;
          top: 50%;
          transform: translateY(-50%);
          background: transparent;
          border: none;
          cursor: pointer;
          padding: 0;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        
        .navbar-search button svg {
          width: 14px;
          height: 14px;
          color: rgba(255, 255, 255, 0.5);
          transition: color 0.3s;
        }
        
        .navbar-search button:hover svg {
          color: white;
        }
        
        /* Actions Buttons */
        .navbar-actions {
          display: flex;
          align-items: center;
          gap: 12px;
          flex-shrink: 0;
        }
        
        .nav-btn-login {
          display: flex;
          align-items: center;
          gap: 6px;
          padding: 6px 14px;
          background: linear-gradient(135deg, #a855f7, #7c3aed);
          border-radius: 30px;
          color: white;
          text-decoration: none;
          font-size: 0.75rem;
          font-weight: 500;
          transition: all 0.3s;
          white-space: nowrap;
        }
        
        .nav-btn-login svg {
          width: 14px;
          height: 14px;
        }
        
        .nav-btn-login:hover {
          transform: scale(1.02);
          box-shadow: 0 0 12px rgba(168, 85, 247, 0.4);
        }
        
        /* Mobile Menu Button */
        .mobile-menu-btn {
          display: none;
          background: transparent;
          border: none;
          cursor: pointer;
          padding: 8px;
        }
        
        .mobile-menu-btn svg {
          width: 20px;
          height: 20px;
          color: white;
        }
        
        /* Responsive */
        @media (max-width: 768px) {
          .auth-navbar {
            padding: 0 15px;
            height: 52px;
          }
          
          .navbar-links {
            display: none;
          }
          
          .navbar-search {
            max-width: 200px;
          }
          
          .navbar-search input {
            font-size: 0.7rem;
            padding: 5px 28px 5px 32px;
          }
          
          .navbar-search button svg {
            width: 12px;
            height: 12px;
          }
          
          .nav-btn-login span {
            display: none;
          }
          
          .nav-btn-login {
            padding: 6px 10px;
          }
          
          .mobile-menu-btn {
            display: flex;
            align-items: center;
            justify-content: center;
          }
          
          .logo-text {
            font-size: 1rem;
          }
          
          .logo-icon {
            font-size: 1.2rem;
          }
        }
        
        @media (max-width: 480px) {
          .navbar-search {
            max-width: 150px;
          }
          
          .navbar-search input {
            width: 100%;
          }
        }
      `}</style>
    </>
  );
}
